#include <iostream>
using namespace std;

class Complex {
private:
 int real, imag;
public:
 Complex(int r = 0, int i = 0) {
 real = r;
 imag = i;
 }
 // Friend function declaration
 friend Complex add(Complex c1, Complex c2);

 void display() {
 cout << real << " + " << imag << "i" << endl;
 }
};

// Friend function definition (not a member function)
Complex add(Complex c1, Complex c2) {
 Complex result;
 result.real = c1.real + c2.real; // Accessing private members
 result.imag = c1.imag + c2.imag;
 return result;
}

int main() {
 Complex c1(3, 4), c2(5, 6), c3;
 c3 = add(c1, c2); // Called like normal function
 cout << "c1: "; c1.display();
 cout << "c2: "; c2.display();
 cout << "Sum: "; c3.display();
 return 0;
}

#include <iostream>
using namespace std;

class Student {
private:
 string name;
 int marks;
public:
 Student(string n, int m) {
 name = n;
 marks = m;
 }
 // Granting access to Result class
 friend class Result;
};

class Result {
public:
 void display(Student s) {
 // Can access private members of Student
 cout << "Student: " << s.name << endl;
 cout << "Marks: " << s.marks << endl;
 }

 void modify(Student &s, int newMarks) {
 s.marks = newMarks; // Directly modifying private member
 }
};

int main() {
 Student s1("John", 85);
 Result r;
 r.display(s1);
 r.modify(s1, 90);
 cout << "After modification: ";
 r.display(s1);
 return 0;
}

#include <iostream>
using namespace std;

class Distance {
private:
 int feet, inches;
public:
 Distance(int f = 0, int i = 0) {
 feet = f;
 inches = i;
 }
 // Friend function for operator overloading
 friend Distance operator+(Distance d1, Distance d2);

 void display() {
 cout << feet << " feet " << inches << " inches" << endl;
 }
};

// Overloading + using friend function
Distance operator+(Distance d1, Distance d2) {
 Distance temp;
 temp.feet = d1.feet + d2.feet;
 temp.inches = d1.inches + d2.inches;
 return temp;
}

int main() {
 Distance d1(5, 8), d2(3, 6), d3;
 d3 = d1 + d2; // Using + operator
 d1.display();
 cout << " + ";
 d2.display();
 cout << " = ";
 d3.display();
 return 0;
}
